export async function fetchAirQuality(city: string) {
  const token = "9974f37d61d6669ec6fca5c7e5f4656530f0c687";
  const cityQuery = city.toLowerCase();

  try {
    const res = await fetch(
      `https://api.waqi.info/feed/${cityQuery}/?token=${token}`,
    );
    if (!res.ok) throw new Error("Network error");

    const data = await res.json();

    if (data.status !== "ok") {
      // kthe null në vend të hedhjes së error
      console.warn(`API error for ${city}: ${data.status}`);
      return null;
    }

    return data.data;
  } catch (err) {
    console.error(`Fetch failed for ${city}:`, err);
    return null;
  }
}
